<script lang="ts">
  import type { PlaySession,ChatMessage,SessionSnapshot } from '@simbot/session';
  import type { CardAsset } from '@simbot/card';
  import Icon from '@simbot/ui/Icon.svelte';
  import { renderDisplayContent } from './display-macros';
  import { alternateForward } from './card-library';
  import { toFactLine } from './FactReceipt.svelte';
  import { presentNarrativeIssues } from './narrative-issues';

  let {session,version,greetings=[],cardName,userName='나',model,waiting=false,assets=[],assetWidth=32,portraitFor,onassetneeded=()=>{},onchange,oncontinue,onerror=()=>{}}:{session:PlaySession;version:number;greetings?:string[];cardName:string;userName?:string;model:string;waiting?:boolean;assets?:CardAsset[];assetWidth?:number;portraitFor:(id:string,emotion?:string)=>string|null;onassetneeded?:(name:string)=>void;onchange:()=>void;oncontinue?:()=>Promise<void>;onerror?:(message:string)=>void}=$props();
  let editing=$state<string|null>(null),draft=$state(''),rerolling=$state(false),translating=$state<string|null>(null),translationShown=$state<Record<string,boolean>>({}),detailsFor=$state<string|null>(null),alternateIndex=$state(0),greetingIndex=$state(0),latest=$state.raw<SessionSnapshot|null>(null),lastSessionId=$state(''),live=$state(0),menuFor=$state<string|null>(null),issuesOpen=$state(false);
  $effect(()=>{void version;if(lastSessionId!==session.id){lastSessionId=session.id;alternateIndex=session.alternateCount;greetingIndex=Math.max(0,greetings.indexOf(session.messages[0]?.content??''));latest=null;issuesOpen=false;cancel();return;}if(alternateIndex>session.alternateCount)alternateIndex=session.alternateCount;});
  $effect(()=>session.subscribe(()=>{live+=1;}));
  let messages=$derived.by(()=>{void version;void live;return session.messages;}),facts=$derived.by(()=>{void version;void live;return session.lastLogs.map(toFactLine);}),narrativeWarning=$derived.by(()=>{void version;void live;const last=session.messages.at(-1);return last?.role==='assistant'?presentNarrativeIssues(last.content,session.narrativeIssues).warning:null;});
  const guard=(work:()=>Promise<void>)=>work().catch(e=>onerror(e instanceof Error?e.message:String(e)));
  function name(message:ChatMessage){return message.role==='user'?userName:cardName;}
  export function displayMacros(content:string,user:string,char:string){return content.replace(/{{\s*user\s*}}/gi,user).replace(/{{\s*char\s*}}/gi,char);}
  function rendered(message:ChatMessage){const result=renderDisplayContent(message.content,userName,cardName,assets,session.regexScripts,session.cbsVariables,message.index,session.messages.length-1);for(const warning of result.warnings)if(warning.code==='asset_missing')onassetneeded(warning.name);return result.html;}
  function cancel(){editing=null;draft='';}
  async function save(message:ChatMessage){if(draft.trim()&&draft!==message.content)await session.editMessage(message.id,draft);cancel();onchange();}
  async function toggleEdit(message:ChatMessage){if(editing===message.id){await save(message);return;}editing=message.id;draft=message.content;}
  function handleEditKey(event:KeyboardEvent,message:ChatMessage){if(event.key==='Escape'){event.preventDefault();cancel();}else if(event.key==='Enter'&&(event.ctrlKey||event.metaKey)){event.preventDefault();void guard(()=>save(message));}}
  async function remove(message:ChatMessage,cascade=false){menuFor=null;if(!confirm(cascade?'이 메시지 이후를 전부 삭제할까요?':'이 메시지를 삭제할까요?'))return;await session.removeMessage(message.id,cascade);onchange();}
  async function left(){if(alternateIndex<=0)return;rerolling=true;try{if(alternateIndex===session.alternateCount)latest=session.snapshot();await session.showAlternate(--alternateIndex);onchange();}finally{rerolling=false;}}
  async function right(){rerolling=true;try{const action=alternateForward(alternateIndex,session.alternateCount);if(action.kind==='show'){alternateIndex=action.index;if(action.index===session.alternateCount&&latest){session.restore(latest);await session.save();}else await session.showAlternate(action.index);}else{await session.reroll();alternateIndex=session.alternateCount;latest=session.snapshot();}onchange();}finally{rerolling=false;}}
  async function rerollIssue(){rerolling=true;try{await session.reroll();alternateIndex=session.alternateCount;latest=session.snapshot();issuesOpen=false;onchange();}finally{rerolling=false;}}
  async function greeting(delta:number){greetingIndex=(greetingIndex+delta+greetings.length)%greetings.length;await session.replaceGreeting(greetings[greetingIndex]!);onchange();}
  function runFor(message:ChatMessage){return session.promptRuns.find(run=>run.id.endsWith(`:${message.id}`));}
  async function translate(message:ChatMessage){if(translationShown[message.id]){translationShown[message.id]=false;return;}translating=message.id;try{await session.translateMessage(message.id,'한국어');translationShown[message.id]=true;onchange();}finally{translating=null;}}
  function tokenLabel(message:ChatMessage){const run=runFor(message);if(!run)return'';return `${run.tokensEstimated?'≈':''}${(run.inputTokens??0)+(run.outputTokens??0)} tok`;}
</script>

<div class="list">
  {#each messages as message,index(message.id)}
    <article class="message" class:user={message.role==='user'}>
      <div class="avatar">{#if portraitFor(message.role==='assistant'?cardName:'user')}<img src={portraitFor(message.role==='assistant'?cardName:'user')!} alt=""/>{:else}{name(message).slice(0,1)}{/if}</div>
      <div class="body">
        <div class="head"><strong>{name(message)}</strong><div class="tools"><button title={editing===message.id?'편집 저장':'편집'} onclick={()=>void guard(()=>toggleEdit(message))}><Icon name="pencil"/></button><button title="복사" onclick={()=>navigator.clipboard.writeText(message.content)}><Icon name="copy"/></button><button title="삭제" onclick={()=>void guard(()=>remove(message))}><Icon name="trash"/></button><button title="더보기" onclick={()=>menuFor=menuFor===message.id?null:message.id}><Icon name="ellipsis"/></button>{#if menuFor===message.id}<div class="menu"><button onclick={()=>void guard(()=>remove(message,true))}>이 메시지 이후 전부 삭제</button></div>{/if}</div></div>
        {#if editing===message.id}
          <div class="editor"><textarea bind:value={draft} onkeydown={(event)=>handleEditKey(event,message)}></textarea><div><button onclick={()=>void guard(()=>save(message))}>저장</button><button onclick={cancel}>취소</button></div></div>
        {:else}<div class="text" style={`--asset-width:${assetWidth}rem`}>{@html rendered(message)}</div>{#if translationShown[message.id]&&message.translation}<div class="translation"><small>번역</small><div class="text" style={`--asset-width:${assetWidth}rem`}>{@html renderDisplayContent(message.translation,userName,cardName,assets,session.regexScripts,session.cbsVariables,message.index,session.messages.length-1).html}</div></div>{/if}{/if}
        {#if message.role==='assistant'}<div class="meta">{#if message.origin==='model'}<span class="model"><Icon name="bot" size={13}/>{model}</span>{/if}<button class:active={translationShown[message.id]} disabled={translating===message.id} onclick={()=>void guard(()=>translate(message))}>{translating===message.id?'번역 중…':'번역'}</button>{#if messages.length===1&&greetings.length>1}<span class="swipe"><button onclick={()=>void guard(()=>greeting(-1))}><Icon name="left"/></button><b>{greetingIndex+1}/{greetings.length}</b><button onclick={()=>void guard(()=>greeting(1))}><Icon name="right"/></button></span>{:else if index===messages.length-1&&message.origin==='model'}<span class="swipe"><button title="이전 응답" disabled={rerolling||alternateIndex===0} onclick={()=>void guard(left)}><Icon name="left"/></button><b>{alternateIndex+1}/{session.alternateCount+1}</b><button title="다음 응답 · 끝에서는 새로 생성" disabled={rerolling||!session.checkpointDepth} onclick={()=>void guard(right)}><Icon name="right"/></button></span>{/if}{#if tokenLabel(message)}<span class="tokens">{tokenLabel(message)}</span><button title="응답 메타데이터" onclick={()=>detailsFor=detailsFor===message.id?null:message.id}>정보</button>{/if}{#if index===messages.length-1&&message.origin==='model'&&oncontinue}<button disabled={waiting} onclick={()=>void oncontinue?.()}>계속 생성</button>{/if}</div>{#if detailsFor===message.id&&runFor(message)}{@const run=runFor(message)!}<section class="run-detail"><header><strong>응답 정보</strong><button onclick={()=>detailsFor=null}>닫기</button></header><dl><div><dt>프로바이더</dt><dd>{run.provider??'알 수 없음'}</dd></div><div><dt>모델</dt><dd>{run.model??model}</dd></div><div><dt>입력 토큰</dt><dd>{run.tokensEstimated?'약 ':''}{run.inputTokens??'-'}</dd></div><div><dt>출력 토큰</dt><dd>{run.tokensEstimated?'약 ':''}{run.outputTokens??'-'}</dd></div><div><dt>소요 시간</dt><dd>{run.durationMs===undefined?'-':`${(run.durationMs/1000).toFixed(1)}초`}</dd></div><div><dt>생성 시각</dt><dd>{new Date(run.createdAt).toLocaleString()}</dd></div>{#if run.finishReason}<div><dt>종료 이유</dt><dd>{run.finishReason}</dd></div>{/if}{#if run.generationId}<div><dt>생성 ID</dt><dd>{run.generationId}</dd></div>{/if}</dl><details><summary>이 응답에 사용한 프롬프트</summary>{#if run.prompt}<pre>{run.prompt.messages.map(item=>`[${item.role}]\n${item.content}`).join('\n\n')}</pre>{:else}<p>오래된 실행은 감사용 해시만 보존합니다. {run.promptHash??''}</p>{/if}</details></section>{/if}{/if}
        {#if message.role==='assistant'&&index===messages.length-1&&(facts.length||narrativeWarning)}<div class="chips">{#each facts as fact}<span class:rejected={fact.rejected}><Icon name={fact.rejected?'blocked':'star'} size={12}/><i>{fact.label}</i><b>{fact.delta??''}</b></span>{/each}{#if narrativeWarning}<button class="issue-chip" class:strong={narrativeWarning.strong} aria-expanded={issuesOpen} onclick={()=>issuesOpen=!issuesOpen}><Icon name="alert" size={12}/>{narrativeWarning.label}</button>{/if}</div>{#if narrativeWarning&&issuesOpen}<section class="issue-detail" class:strong={narrativeWarning.strong} aria-label="서사 검증 경고"><ul>{#each narrativeWarning.details as detail}<li>{detail}</li>{/each}</ul><button disabled={rerolling||!session.checkpointDepth} onclick={()=>void guard(rerollIssue)}><Icon name="refresh" size={13}/> 리롤</button></section>{/if}{/if}
      </div>
    </article>
  {/each}
  {#if waiting}<article class="message typing" aria-label="응답 작성 중"><div class="avatar">{cardName.slice(0,1)}</div><div class="dots"><i></i><i></i><i></i></div></article>{/if}
</div>

<style>
  .list{padding:26px 20px 120px}.message{display:grid;grid-template-columns:56px minmax(0,1fr);gap:16px;margin:0 auto 22px;max-width:900px}.avatar{width:56px;height:56px;border-radius:6px;background:#292d36;display:grid;place-items:center;font:700 20px sans-serif;overflow:hidden;box-shadow:0 2px 8px #0006}.avatar img{width:100%;height:100%;object-fit:cover}.head{display:flex;align-items:center;gap:8px;min-height:27px}.head strong{font-size:18px}.tools{margin-left:auto;display:flex;position:relative}.tools button,.swipe button{display:grid;place-items:center;border:0;background:transparent;color:#858b98;padding:4px;transition:.12s}.tools button:hover,.swipe button:hover{color:#78a2ff}.tools button:active,.swipe button:active{transform:scale(.9)}button:focus-visible{outline:2px solid #6c98f4;outline-offset:2px}.menu{position:absolute;right:0;top:100%;z-index:5;min-width:210px;padding:4px;border:1px solid #3a4150;border-radius:7px;background:#1c2029}.menu button{width:100%;padding:8px;color:#ddd}.text{color:#e7e0d4;font:15.5px/1.65 Georgia,'Noto Serif KR',serif}.user .text{font-family:system-ui,sans-serif;color:#d9dde7}.text :global(p){margin:2px 0 10px}.text :global(.dialogue){color:#e5bf79}.text :global(pre){overflow:auto;padding:12px;border-radius:7px;background:#0d0f13}.text :global(code){font:13px ui-monospace;background:#252932;padding:1px 4px;border-radius:3px}.text :global(blockquote){margin:8px 0;padding-left:12px;border-left:3px solid #6d7890;color:#b8bdc7}.text :global(a){color:#8fb3ff}.text :global(img){max-width:100%;height:auto;border-radius:8px}.text :global(.illust){max-width:560px;margin:8px 0;border:1px solid #353942;border-radius:8px;overflow:hidden}.text :global(.illust img){display:block;width:100%;height:auto}.text :global(figcaption){padding:6px 10px;font:11px ui-monospace;color:#8d94a2}.body textarea{width:100%;min-height:110px;padding:10px;background:#191c22;color:#eee;border:1px solid #6793ef}.editor>div{display:flex;justify-content:flex-end;gap:6px;margin-top:6px}.editor button{padding:5px 11px;border:1px solid #414754;border-radius:5px;background:#222630;color:#ddd}.meta{display:flex;justify-content:flex-end;align-items:center;gap:12px;margin-top:5px;font:11px sans-serif;color:#727887}.model,.swipe{display:flex;align-items:center;gap:5px}.model{padding:3px 7px;border-radius:8px}.chips{display:flex;gap:6px;flex-wrap:wrap;margin-top:8px}.chips span{display:flex;align-items:center;gap:5px;border:1px solid #3b4149;border-left:2px solid #d8b36a;border-radius:5px;padding:3px 8px;font:11px ui-monospace;color:#dce0e6}.chips i{font-style:normal;color:#9299a7}.chips .rejected{border-left-color:#d06d55;color:#e0a7b0}.issue-chip{display:flex;align-items:center;gap:5px;border:1px solid #8d713c;border-left:2px solid #d8b36a;border-radius:5px;padding:3px 8px;background:#2c281f;color:#e3c78f;font:11px ui-monospace;cursor:pointer}.issue-chip.strong{border-color:#9c5048;background:#351f22;color:#f0aaa3}.issue-detail{margin-top:7px;padding:9px 11px;border:1px solid #806634;border-radius:6px;background:#242119;color:#d9c8a7;font:12px/1.5 sans-serif}.issue-detail.strong{border-color:#9c5048;background:#2e1d20;color:#efb3ad}.issue-detail ul{margin:0 0 8px;padding-left:18px}.issue-detail button{display:flex;align-items:center;gap:5px;border:1px solid currentColor;border-radius:5px;padding:4px 9px;background:transparent;color:inherit;cursor:pointer}.typing{align-items:center}.dots{display:flex;gap:5px;padding:20px 4px}.dots i{width:7px;height:7px;border-radius:50%;background:#8e96a6;animation:pulse 1s infinite}.dots i:nth-child(2){animation-delay:.15s}.dots i:nth-child(3){animation-delay:.3s}@keyframes pulse{50%{opacity:.25;transform:translateY(-3px)}}@media(prefers-reduced-motion:reduce){.dots i{animation:none}}@media(max-width:680px){.list{padding-inline:10px}.message{grid-template-columns:42px 1fr;gap:10px}.avatar{width:42px;height:42px}}
  .text :global(img){max-width:min(100%,var(--asset-width,32rem))}.text :global(.illust){max-width:min(100%,var(--asset-width,32rem))}.translation{margin-top:10px;padding:10px 12px;border-left:2px solid #6c98f4;background:#171b23}.translation>small{display:block;margin-bottom:6px;color:#8fb3ff;font:10px ui-monospace}.meta button{border:0;border-radius:4px;padding:3px 6px;background:transparent;color:#7f8796;font:11px sans-serif;cursor:pointer}.meta button:hover,.meta button.active{background:#252b36;color:#a8c2ff}.tokens{font:10px ui-monospace;color:#8b93a2}.run-detail{margin-top:7px;padding:10px;border:1px solid #39404d;border-radius:7px;background:#171a20;color:#cfd4de;font:12px sans-serif}.run-detail header{display:flex;justify-content:space-between;align-items:center}.run-detail header button{border:0;background:transparent;color:#9299a7}.run-detail dl{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:5px 14px}.run-detail dl div{display:flex;justify-content:space-between;gap:12px}.run-detail dt{color:#818a99}.run-detail dd{margin:0;text-align:right;overflow-wrap:anywhere}.run-detail details{margin-top:8px}.run-detail pre{max-height:280px;overflow:auto;white-space:pre-wrap;background:#0e1014;padding:10px;border-radius:5px;font:11px/1.45 ui-monospace}
</style>
